  ('real-estate-moex-01083', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '設定抵押權時，土地及其土地上之建築物，同屬於一人所有，而以土地及建築物為抵押者，如經拍賣， 其土地與建築物之拍定人各異時，關於拍定人間之關係，下列敘述何者正確：', '["視為已有不動產役權之設定", "視為已有地上權之設定", "視為取得使用借貸權", "視為取得租賃權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
